### 四、STL 算法精选

```cpp
#include <algorithm>
#include <numeric>

std::vector<double> data = {3.0, 1.0, 4.0, 1.0, 5.0, 9.0};

// 排序
std::sort(data.begin(), data.end());  // 升序
std::sort(data.begin(), data.end(), std::greater<>());  // 降序

// 变换
std::vector<double> radians(data.size());
std::transform(data.begin(), data.end(), radians.begin(),
    [](double deg) { return deg * M_PI / 180; });

// 过滤（C++20 的 ranges 更方便，这里用 erase-remove 惯用法）
data.erase(
    std::remove_if(data.begin(), data.end(),
        [](double x) { return x < 2.0; }),
    data.end());

// 累积
double sum = std::accumulate(data.begin(), data.end(), 0.0);
double product = std::accumulate(data.begin(), data.end(), 1.0,
    std::multiplies<>());

// 查找
auto [min_it, max_it] = std::minmax_element(data.begin(), data.end());
bool all_positive = std::all_of(data.begin(), data.end(),
    [](double x) { return x > 0; });

// 数值算法
std::vector<double> prefix_sum(data.size());
std::partial_sum(data.begin(), data.end(), prefix_sum.begin());
std::vector<double> diffs(data.size());
std::adjacent_difference(data.begin(), data.end(), diffs.begin());
```

