// gpio_controller.h
#include <string>
#include <stdexcept>
#include <fstream>
#include <iostream>

class GPIOController {
public:
    enum class Direction { INPUT, OUTPUT };

    // 构造: 初始化 GPIO 引脚
    GPIOController(int pin, Direction dir) : pin_(pin) {
        // 导出引脚
        std::ofstream export_file("/sys/class/gpio/export");
        if (!export_file) throw std::runtime_error("Cannot export GPIO");
        export_file << pin;

        // 设置方向
        std::string dir_path = "/sys/class/gpio/gpio" + std::to_string(pin) + "/direction";
        std::ofstream dir_file(dir_path);
        dir_file << (dir == Direction::OUTPUT ? "out" : "in");

        // 打开值文件
        std::string val_path = "/sys/class/gpio/gpio" + std::to_string(pin) + "/value";
        value_file_.open(val_path);

        std::cout << "GPIO " << pin << " initialized" << std::endl;
    }

    // 析构: 自动释放引脚
    ~GPIOController() {
        value_file_.close();
        std::ofstream unexport("/sys/class/gpio/unexport");
        unexport << pin_;
        std::cout << "GPIO " << pin_ << " released" << std::endl;
    }

    void write(bool high) {
        value_file_ << (high ? "1" : "0") << std::flush;
    }

    // 禁止拷贝
    GPIOController(const GPIOController&) = delete;
    GPIOController& operator=(const GPIOController&) = delete;

private:
    int pin_;
    std::fstream value_file_;
};

