**1. DH 参数法正运动学**

```cpp
#include <Eigen/Dense>
#include <vector>
#include <cmath>
#include <iostream>

struct DHParams {
    double a, alpha, d, theta_offset;
};

Eigen::Matrix4d dh_transform(const DHParams& p, double theta) {
    double q = theta + p.theta_offset;
    double cq = cos(q), sq = sin(q);
    double ca = cos(p.alpha), sa = sin(p.alpha);
    Eigen::Matrix4d T;
    T << cq, -sq*ca,  sq*sa, p.a*cq,
         sq,  cq*ca, -cq*sa, p.a*sq,
         0,   sa,     ca,    p.d,
         0,   0,      0,     1;
    return T;
}

Eigen::Matrix4d forward_kinematics(const std::vector<DHParams>& dh,
                                     const Eigen::VectorXd& q) {
    Eigen::Matrix4d T = Eigen::Matrix4d::Identity();
    for (int i = 0; i < (int)dh.size(); ++i) {
        T = T * dh_transform(dh[i], q(i));
    }
    return T;
}

