#include <tuple>
#include <cmath>

// 加权平均融合任意数量的传感器读数
template<typename T>
T weighted_average(T value, double weight) {
    return value * weight;
}

template<typename T, typename... Rest>
T weighted_average(T first_val, double first_weight, 
                    Rest... rest) {
    return first_val * first_weight + weighted_average(rest...);
}

